// Get all items from previous node
const allItems = $input.all();

// Flatten everything into one array (each item.json is an ad)
const ads = allItems.map(item => item.json);

// Prepare campaign grouping
const campaigns = {};

for (const ad of ads) {
  const {
    campaign_id,
    campaign_name,
    adset_id,
    adset_name,
    ad_id,
    ad_name,
    spend,
    reach,
    impressions,
    clicks,
    ctr,
    cpc,
    cpm,
    date_start,
    date_stop,
    results
  } = ad;

  // --- Group by Campaign ---
  if (!campaigns[campaign_id]) {
    campaigns[campaign_id] = {
      campaign_id,
      campaign_name,
      adsets: {}
    };
  }

  // --- Group by Adset ---
  if (!campaigns[campaign_id].adsets[adset_id]) {
    campaigns[campaign_id].adsets[adset_id] = {
      adset_id,
      adset_name,
      ads: []
    };
  }

  // --- Add Ad ---
  campaigns[campaign_id].adsets[adset_id].ads.push({
    ad_id,
    ad_name,
    metrics: {
      spend,
      reach,
      impressions,
      clicks,
      ctr,
      cpc,
      cpm
    },
    results,
    date: {
      start: date_start,
      stop: date_stop
    }
  });
}

// Convert nested objects to arrays
const output = Object.values(campaigns).map(campaign => ({
  ...campaign,
  adsets: Object.values(campaign.adsets)
}));

// Return final grouped data
return [{ json: { campaigns: output } }];

